-- Prompt 30 gym-scoped customer mapping and idempotent subscription webhooks.
begin;set local role service_role;select set_config('request.jwt.claim.role','service_role',true);
select public.upsert_stripe_billing_customer('30000000-0000-4000-8000-000000000001','cus_TestGym123','billing@crux.example.invalid');
do $$declare first_result boolean;duplicate_result boolean;begin first_result:=public.apply_stripe_subscription_event('evt_TestEvent123','customer.subscription.created',false,'cus_TestGym123','sub_TestSubscription123','price_TestPrice123','trialing',now(),now()+interval'30 days',false,null,now()+interval'14 days','starter');duplicate_result:=public.apply_stripe_subscription_event('evt_TestEvent123','customer.subscription.created',false,'cus_TestGym123','sub_TestSubscription123','price_TestPrice123','active',now(),now()+interval'30 days',false,null,null,'starter');if first_result is not true or duplicate_result is not false then raise exception'Stripe event idempotency failed';end if;if(select count(*)from public.stripe_billing_events where id='evt_TestEvent123')<>1 or(select status from public.subscriptions where stripe_subscription_id='sub_TestSubscription123')<>'trialing'then raise exception'Duplicate event changed projection';end if;if(select gym_id from public.subscriptions where stripe_subscription_id='sub_TestSubscription123')<>'30000000-0000-4000-8000-000000000001'then raise exception'Subscription was not gym scoped';end if;end$$;
set local role authenticated;select set_config('request.jwt.claim.role','authenticated',true);select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000004',true);do $$begin if exists(select 1 from public.billing_customers where stripe_customer_id='cus_TestGym123')or exists(select 1 from public.subscriptions where stripe_subscription_id='sub_TestSubscription123')then raise exception'Member accessed gym billing';end if;end$$;
select set_config('request.jwt.claim.sub','10000000-0000-4000-8000-000000000001',true);do $$begin if not exists(select 1 from public.billing_customers where gym_id='30000000-0000-4000-8000-000000000001'and stripe_customer_id='cus_TestGym123')or not exists(select 1 from public.subscriptions where gym_id='30000000-0000-4000-8000-000000000001'and stripe_subscription_id='sub_TestSubscription123')then raise exception'Owner cannot read gym billing';end if;end$$;
set local role service_role;do $$begin if not exists(select 1 from public.audit_logs where action='billing.subscription.updated'and gym_id='30000000-0000-4000-8000-000000000001')then raise exception'Billing audit missing';end if;end$$;
rollback;
